const article=document.querySelector(".blog-article-wrapper, .blog-article");if(article){const e=document.createElement("div");e.className="reading-progress",document.body.append(e);const t=()=>{const t=article.getBoundingClientRect(),a=article.offsetHeight-window.innerHeight,n=Math.min(1,Math.max(0,-t.top/Math.max(a,1)));e.style.transform=`scaleX(${n})`};window.addEventListener("scroll",t,{passive:!0}),t()}